// Validate that we have the required fields before writing to D1.
const ctx = $input.first().json;

if (!ctx.topic_slug || !ctx.date_key || !ctx.publish_job_id) {
  throw new Error(`Missing required fields for D1 update: topic_slug=${ctx.topic_slug}, date_key=${ctx.date_key}, publish_job_id=${ctx.publish_job_id}`);
}

return [{ json: ctx }];

