// Confirm both D1 writes succeeded and return the final result.
const ctx = $('Validate Input').first().json;
const statusResp = $('Update daily_status in D1').first().json;
const jobResp = $('Update publish_jobs in D1').first().json;

if (!statusResp?.success) {
  throw new Error(`D1 daily_status update failed for ${ctx.topic_slug}/${ctx.date_key}: ${JSON.stringify(statusResp?.errors)}`);
}
if (!jobResp?.success) {
  throw new Error(`D1 publish_jobs update failed for publish_job_id=${ctx.publish_job_id}: ${JSON.stringify(jobResp?.errors)}`);
}

return [{
  json: {
    topic_slug: ctx.topic_slug,
    date_key: ctx.date_key,
    publish_job_id: ctx.publish_job_id,
    github_commit_sha: ctx.github_commit_sha || null,
    page_state: 'published',
    status: 'success'
  }
}];

